extra.modelCss:
/* Flexbox 2: tamanhos e wrap */

.layout {
  display: flex;
  gap: 16px;
}

.sidebar {
  flex: 0 0 280px; /* fixo */
}

.main {
  flex: 1; /* cresce */
}

.cards {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
}

.card {
  flex: 1 1 260px; /* cresce, encolhe, base */
  padding: 16px;
  border: 1px solid #ddd;
  border-radius: 14px;
}
